/** Single symbol token */
export function SlotSymbol({ symbolKey, size = 96, style = {}, className = "" }) {
  const sym = SYMBOLS[symbolKey]
  if (!sym) return null
  return (
    <div
      className={className}
      style={{
        width: size,
        height: size,
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
        overflow: "hidden",
        ...style,
      }}
    >
      <img
        src={sym.src}
        alt={sym.label}
        draggable={false}
        style={{
          width: "100%",
          height: "100%",
          objectFit: "contain",
          imageRendering: "pixelated",
          display: "block",
        }}
      />
    </div>
  )
}

/** All symbol keys in order */
export const SYMBOL_KEYS = Object.keys(SYMBOLS)



/** Symbol metadata without base64 src */
export const SYMBOL_META = Object.fromEntries(
  Object.entries(SYMBOLS).map(([k, v]) => [k, { id: v.id, label: v.label }])
)

export default SYMBOLS
